package cat.hajoya.piratasdeandromeda.ui.joc

import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.DialogFragment
import androidx.fragment.app.activityViewModels
import cat.hajoya.piratasdeandromeda.R
import cat.hajoya.piratasdeandromeda.databinding.ExitGameFrBinding
import cat.hajoya.piratasdeandromeda.ui.preparacio.StartPartidaFragment
import cat.hajoya.piratasdeandromeda.viewmodels.GameViewModel

/**
 * Dialog de confirmación para abandonar la partida.
 * - "Seguir luchando" → dismiss
 * - "Abandonar" → leaveGame + volver a StartPartidaFragment (estado inicial)
 */
class ExitGameDialogFragment : DialogFragment() {

    private var _binding: ExitGameFrBinding? = null
    private val binding get() = _binding!!

    private val gameViewModel: GameViewModel by activityViewModels()

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?,
    ): View {
        _binding = ExitGameFrBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        binding.btnStay.setOnClickListener {
            dismiss()
        }

        binding.btnExit.setOnClickListener {
            confirmExit()
        }
    }

    private fun confirmExit() {
        // Llamar to leaveGame para limpiar recursos del servidor
        gameViewModel.leaveGame()

        // Limpiar datos de la partida en el ViewModel
        gameViewModel.resetGameData()

        // Limpiar todo el back stack y volver a StartPartidaFragment (estado inicial)
        // Esto es como si acabaras de iniciar sesión: datos frescos, navegación limpia
        parentFragmentManager.popBackStack(null, androidx.fragment.app.FragmentManager.POP_BACK_STACK_INCLUSIVE)

        // Navegar a StartPartidaFragment (como si fuera el primer fragmento)
        parentFragmentManager.beginTransaction()
            .replace(R.id.fragment_container, StartPartidaFragment())
            .commit()

        dismiss()
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }

    companion object {
        const val TAG = "ExitGameDialog"
        fun newInstance() = ExitGameDialogFragment()
    }
}

package cat.hajoya.piratasdeandromeda.ui.joc

import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.DialogFragment
import androidx.fragment.app.activityViewModels
import cat.hajoya.piratasdeandromeda.R
import cat.hajoya.piratasdeandromeda.databinding.ExitGameFrBinding
import cat.hajoya.piratasdeandromeda.ui.preparacio.StartPartidaFragment
import cat.hajoya.piratasdeandromeda.viewmodels.GameViewModel

/**
 * Dialog de confirmación para abandonar la partida.
 * - "Seguir luchando" → dismiss
 * - "Abandonar" → leaveGame + volver a StartPartidaFragment (estado inicial)
 */
class ExitGameDialogFragment : DialogFragment() {

    private var _binding: ExitGameFrBinding? = null
    private val binding get() = _binding!!

    private val gameViewModel: GameViewModel by activityViewModels()

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?,
    ): View {
        _binding = ExitGameFrBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        binding.btnStay.setOnClickListener {
            dismiss()
        }

        binding.btnExit.setOnClickListener {
            confirmExit()
        }
    }

    private fun confirmExit() {
        // Llamar a leaveGame para limpiar recursos del servidor y estado de la partida
        gameViewModel.leaveGame()

        // Limpiar todo el back stack y volver a StartPartidaFragment (estado inicial)
        // Esto es como si acabaras de iniciar sesión: datos frescos, navegación limpia
        parentFragmentManager.popBackStack(null, androidx.fragment.app.FragmentManager.POP_BACK_STACK_INCLUSIVE)

        // Navegar a StartPartidaFragment (como si fuera el primer fragmento)
        parentFragmentManager.beginTransaction()
            .replace(R.id.fragment_container, StartPartidaFragment())
            .commit()

        dismiss()
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }

    companion object {
        const val TAG = "ExitGameDialog"
        fun newInstance() = ExitGameDialogFragment()
    }
}
